* CICS sign-on screen (default logon transaction)
MAP CSSN SIZE 24x80
  FIELD AT 1,28 LEN 24 PROT BRIGHT COLOR=BLUE      "CSSN SIGN-ON"
  FIELD AT 4,0  LEN 8  PROT COLOR=BLUE             "TERMID:"
  INPUT TERMID   AT 4,11 LEN 8  PROT BRIGHT COLOR=WHITE
  FIELD AT 6,0  LEN 9  PROT                        "Userid:"
  INPUT USERID   AT 6,11 LEN 8  UNDERSCORE COLOR=GREEN
  STOP           AT 6,20
  FIELD AT 8,0  LEN 9  PROT                        "Password:"
  INPUT PASSWORD AT 8,11 LEN 8  HIDDEN UNDERSCORE COLOR=RED
  STOP           AT 8,20
  FIELD AT 12,0 LEN 50 PROT                        "Sign on with ENTER. PF3=Disconnect."
  INPUT MSG      AT 18,0 LEN 60 PROT BRIGHT COLOR=RED
  CURSOR         AT 6,12
ENDMAP
